import java.sql.*;

public class VulnerableCodeSnippet {

    public void retrieveUserData(String username) {
        String query = "SELECT * FROM Users WHERE username = '" + username + "'";

        try {
            Connection conn = DriverManager.getConnection("jdbc:mysql://localhost:3306/mydatabase", "user", "password");
            Statement stmt = conn.createStatement();
            ResultSet rs = stmt.executeQuery(query);

            while (rs.next()) {
                System.out.println("Username: " + rs.getString("username") + ", Email: " + rs.getString("email"));
            }

            conn.close();
        } catch (SQLException e) {
            e.printStackTrace();
        }
    }

    public static void main(String[] args) {
        VulnerableCodeSnippet codeSnippet = new VulnerableCodeSnippet();
        codeSnippet.retrieveUserData("admin'; DROP TABLE Users; --");
    }
}

