import java.sql.*;

public class SecureCodeSnippet {

    public void retrieveUserData(String username) {
        String query = "SELECT * FROM Users WHERE username = ?";

        try {
            Connection conn = DriverManager.getConnection("jdbc:mysql://localhost:3306/mydatabase", "user", "password");
            PreparedStatement pstmt = conn.prepareStatement(query);
            pstmt.setString(1, username);
            ResultSet rs = pstmt.executeQuery();

            while (rs.next()) {
                System.out.println("Username: " + rs.getString("username") + ", Email: " + rs.getString("email"));
            }

            conn.close();
        } catch (SQLException e) {
            e.printStackTrace();
        }
    }

    public static void main(String[] args) {
        SecureCodeSnippet codeSnippet = new SecureCodeSnippet();
        codeSnippet.retrieveUserData("admin'; DROP TABLE Users; --"); // This input is now safe from SQL injection
    }
}

